sql_query:
WITH sales_total AS (
    SELECT SUM(ss.ss_sales_price * ss.ss_quantity) AS total_sales
    FROM store_sales AS ss
)
SELECT COALESCE(total_sales, 0) AS total_sales_revenue
FROM sales_total;

SELECT s_store_name AS store_name
FROM store
ORDER BY s_store_name;

SELECT DISTINCT i.i_category AS category_name
FROM item AS i
ORDER BY i.i_category;
